const input = $input.first().json;
const payload = input.payload ?? input;
if (!payload.recipient_phone || !payload.message) {
  return [{ json: { status: 'error', result: {}, error: 'recipient_phone and message are required' } }];
}
return [{ json: { status: 'success', result: { backend_endpoint: '/api/v1/whatsapp/agent/reply', recipient_phone: payload.recipient_phone, message: payload.message, gym_id: payload.gym_id ?? null }, note: 'Configure HTTP Request with CORDEX_AGENT_SERVICE_TOKEN to send through backend.' } }];
